import json
import re

businesses = locals()['var_function-call-2344055396444565971']

wifi_values = {}
state_counts = {}

state_pattern = re.compile(r" in [^,]+, ([A-Z]{2})")

for b in businesses:
    attrs = b.get('attributes')
    desc = b.get('description', '')

    # Check attributes
    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            s_val = str(wifi_val)
            wifi_values[s_val] = wifi_values.get(s_val, 0) + 1

    match = state_pattern.search(desc)
    if match:
        st = match.group(1)
        state_counts[st] = state_counts.get(st, 0) + 1

print("__RESULT__:")
print(json.dumps({
    "wifi_values_counts": wifi_values,
    "total_states_found": len(state_counts),
    "sample_states": list(state_counts.keys())[:10]
}))

